interface Notification {
  id: string;
  message: string;
  read: boolean;
  createdAt: Date;
}

// In a real application, this would interact with a database.
// For this exercise, we'll use a simple in-memory store to simulate data.
const notifications: Map<string, Notification> = new Map();

// Seed some initial data for demonstration purposes
notifications.set('notif-1', { id: 'notif-1', message: 'Welcome to our service!', read: false, createdAt: new Date() });
notifications.set('notif-2', { id: 'notif-2', message: 'New feature available!', read: false, createdAt: new Date() });
notifications.set('notif-3', { id: 'notif-3', message: 'Your order has shipped.', read: true, createdAt: new Date() }); // Already read

export class NotificationService {
  /**
   * Marks a notification as read.
   * This operation is idempotent: calling it multiple times with the same ID
   * will not cause an error and will result in the same state (the notification being read).
   *
   * @param notificationId The ID of the notification to mark as read.
   * @returns The updated notification object, or `null` if the notification was not found.
   */
  async markAsRead(notificationId: string): Promise<Notification | null> {
    const notification = notifications.get(notificationId);

    if (!notification) {
      // Notification not found, return null.
      return null;
    }

    if (notification.read) {
      // The notification is already marked as read.
      // This ensures idempotency: calling the operation again has no further effect
      // and does not result in an error.
      console.log(`Notification ${notificationId} was already read. No change needed.`);
      return { ...notification }; // Return a copy to prevent external modification
    }

    // Simulate an asynchronous database update
    await new Promise(resolve => setTimeout(resolve, 50)); // Simulate network/DB latency

    notification.read = true;
    notifications.set(notificationId, notification); // Update the in-memory store

    console.log(`Notification ${notificationId} successfully marked as read.`);
    return { ...notification }; // Return a copy of the updated notification
  }

  /**
   * Retrieves a notification by its ID.
   * @param notificationId The ID of the notification to retrieve.
   * @returns The notification object, or `null` if not found.
   */
  async getNotification(notificationId: string): Promise<Notification | null> {
    return notifications.get(notificationId) || null;
  }
}

export const notificationService = new NotificationService();
